+/** A condition accepted by conditional option helpers. */
+export type OptionCondition = string | OptionDependencyCondition | OptionDependency;
+
+function normalizeOptionCondition(condition: OptionCondition): OptionDependency {
+  return typeof condition === "string" ? { option: condition } : condition;
+}
+
+function optionNamesFromSpec(spec: OptionName | readonly OptionName[]): readonly OptionName[] {
+  return typeof spec === "string" ? [spec] : spec;
