+function getOptionDependency(usage: Usage): OptionDependency | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn) return term.dependsOn;
+    if (term.type === "optional" || term.type === "multiple") {
+      const dependency = getOptionDependency(term.terms);
+      if (dependency) return dependency;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const dependency = getOptionDependency(terms);
+        if (dependency) return dependency;
+      }
+    }
+  }
+  return undefined;
+}
+
+function getOptionNamesFromUsage(usage: Usage): readonly string[] {
+  const names: string[] = [];
+  for (const term of usage) {
+    if (term.type === "option") names.push(...term.names);
+    else if (term.type === "optional" || term.type === "multiple") {
+      names.push(...getOptionNamesFromUsage(term.terms));
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) names.push(...getOptionNamesFromUsage(terms));
+    }
+  }
+  return names;
+}
+
+function unwrapConditionalState(state: unknown): { readonly found: boolean; readonly value: unknown } {
+  if (Array.isArray(state)) return state.length === 1
+    ? unwrapConditionalState(state[0])
+    : { found: false, value: undefined };
+  if (isDependencySourceState(state)) return unwrapConditionalState(state.result);
+  if (isDeferredParseState(state)) return unwrapConditionalState(state.preliminaryResult);
+  if (state != null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: unknown; readonly value?: unknown };
+    return result.success === true
+      ? { found: true, value: result.value }
+      : { found: false, value: undefined };
+  }
+  return { found: state !== undefined, value: state };
+}
+
+function evaluateOptionDependency(
+  dependency: OptionDependency,
+  state: Record<string | symbol, unknown> | undefined,
+  fields: ReadonlyMap<string, string | symbol>,
+): boolean {
+  const evaluate = (condition: OptionDependencyCondition): boolean => {
+    const field = fields.get(condition.option);
+    if (field === undefined || state === undefined) return false;
+    const value = unwrapConditionalState(state[field]);
+    if (!value.found) return false;
